import{_ as e,o as a,c as s,a2 as d}from"./chunks/framework.CH-YxFqP.js";const l="/nginx-reverse-emby/screenshots/panel-relay-form.png",r="/nginx-reverse-emby/screenshots/panel-relay-listener.png",n="/nginx-reverse-emby/screenshots/panel-l4-form-basic.png",i="/nginx-reverse-emby/screenshots/panel-l4-relay-form.png",o="/nginx-reverse-emby/screenshots/panel-l4-rule.png",P=JSON.parse('{"title":"L4 规则 + Relay 隧道从 0 到可用","description":"","frontmatter":{},"headers":[],"relativePath":"guide/l4-relay.md","filePath":"guide/l4-relay.md","lastUpdated":1781350447000}'),p={name:"guide/l4-relay.md"};function c(h,t,b,y,m,g){return a(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="l4-规则-relay-隧道从-0-到可用" tabindex="-1">L4 规则 + Relay 隧道从 0 到可用 <a class="header-anchor" href="#l4-规则-relay-隧道从-0-到可用" aria-label="Permalink to &quot;L4 规则 + Relay 隧道从 0 到可用&quot;">​</a></h1><p>这篇教程适合已经会用 HTTP 规则的人。HTTP 规则解决的是浏览器或 Emby 客户端访问 Web 服务的问题；L4 规则处理的是更底层的 TCP/UDP 端口转发。配合 Relay 后，入口节点可以先把 TCP/UDP 流量送进 Relay 隧道，再由中继节点访问后端。</p><p>本文用一个 TCP 示例说明完整路径：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端访问: VPS_A:18096</span></span>
<span class="line"><span>L4 规则入口: local 节点</span></span>
<span class="line"><span>Relay 首跳: relay-fast-vps, relay.example.com:7443</span></span>
<span class="line"><span>最终后端: origin.emby.example.net:8096</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>实际使用时，把域名、端口和后端地址换成你自己的。</p><h2 id="适合什么场景" tabindex="-1">适合什么场景 <a class="header-anchor" href="#适合什么场景" aria-label="Permalink to &quot;适合什么场景&quot;">​</a></h2><ul><li>你有一台优化线路 VPS，想把某个 TCP 服务固定到这台 VPS 的端口上访问。</li><li>后端服务不一定是 HTTP，或者你明确要按 TCP/UDP 端口转发。</li><li>中间链路需要经过 Relay 监听器，而不是让入口节点直接连后端。</li></ul><p>如果你的目标只是反代 Emby Web 页面，优先读 <a href="./http-rule">添加 HTTP 规则</a>。L4 不会理解 HTTP Host、路径、Cookie、302 跳转和证书自动匹配，它只是按端口转发流量。</p><h2 id="你需要先准备" tabindex="-1">你需要先准备 <a class="header-anchor" href="#你需要先准备" aria-label="Permalink to &quot;你需要先准备&quot;">​</a></h2><ul><li>控制面已经通过 <a href="./docker-compose">Docker Compose 部署</a> 启动。</li><li>面板里能看到 <code>local</code> 节点在线，或者你已经接入了要承载入口的远程 Agent。</li><li>Relay 公网入口端口已经在云防火墙和系统防火墙放行，例如 <code>7443</code>。</li><li>L4 对外监听端口已经放行，例如本文示例的 <code>18096</code>。</li><li>承载最终出站的节点能访问后端 <code>origin.emby.example.net:8096</code>。</li></ul><h2 id="_1-创建-relay-监听器" tabindex="-1">1. 创建 Relay 监听器 <a class="header-anchor" href="#_1-创建-relay-监听器" aria-label="Permalink to &quot;1. 创建 Relay 监听器&quot;">​</a></h2><p>进入 <strong>Relay 监听器</strong> 页面，选择 <code>local</code> 或你要作为中继节点的 Agent，然后点击 <strong>新建监听器</strong>。</p><p>核心字段按下面填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td><code>relay-fast-vps</code></td><td>给这条 Relay 入口起一个能看懂的名字。</td></tr><tr><td>监听证书来源</td><td>自动签发（Relay CA）</td><td>新手保持默认，系统会自动维护 Relay CA 和 Pin。</td></tr><tr><td>绑定地址</td><td><code>0.0.0.0</code></td><td>监听所有网卡。</td></tr><tr><td>监听端口</td><td><code>7443</code></td><td>Relay 在这台节点上实际监听的端口。</td></tr><tr><td>公网入口</td><td><code>relay.example.com:7443</code></td><td>其他节点访问这条 Relay 时使用的公网地址。</td></tr><tr><td>Relay Transport</td><td><code>TLS/TCP</code></td><td>新手先用默认值，确认可用后再考虑 QUIC 或 WireGuard。</td></tr></tbody></table><p><img src="`+l+'" alt="创建 Relay 监听器"></p><p>保存后，列表里应该能看到启用状态、监听地址和公网入口。</p><p><img src="'+r+'" alt="Relay 监听器列表"></p><h2 id="_2-创建-l4-规则" tabindex="-1">2. 创建 L4 规则 <a class="header-anchor" href="#_2-创建-l4-规则" aria-label="Permalink to &quot;2. 创建 L4 规则&quot;">​</a></h2><p>进入 <strong>L4 规则</strong> 页面，选择承载入口端口的 Agent，然后点击 <strong>添加 L4 规则</strong>。</p><p>在 <strong>基础配置</strong> 里填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>协议</td><td><code>TCP</code></td><td>Emby/Jellyfin 的普通 Web 端口是 TCP。</td></tr><tr><td>监听地址</td><td><code>0.0.0.0</code></td><td>允许外部访问这个入口端口。</td></tr><tr><td>监听端口</td><td><code>18096</code></td><td>客户端最终访问的 VPS 端口。</td></tr><tr><td>后端服务器</td><td><code>origin.emby.example.net:8096</code></td><td>最终要连接的后端 TCP 服务。</td></tr><tr><td>启用规则</td><td>开启</td><td>保存后规则才会下发。</td></tr></tbody></table><p><img src="'+n+'" alt="L4 基础配置"></p><h2 id="_3-给-l4-规则添加-relay-链路" tabindex="-1">3. 给 L4 规则添加 Relay 链路 <a class="header-anchor" href="#_3-给-l4-规则添加-relay-链路" aria-label="Permalink to &quot;3. 给 L4 规则添加 Relay 链路&quot;">​</a></h2><p>切到 <strong>Relay 配置</strong>，点击 <strong>添加新层</strong>，再选择刚才创建的 <code>relay-fast-vps</code>。界面里会显示：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端 -&gt; 第 1 层 relay-fast-vps -&gt; 后端</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><img src="'+i+'" alt="L4 Relay 配置"></p><p>这里的“层”就是 <code>relay_layers</code>。一层里可以放多个 Relay 监听器作为并行候选；多层表示按顺序逐跳转发。新手先只配一层一个节点，确认可用后再扩展。</p><p>保持规则启用，点击 <strong>创建规则</strong>。</p><h2 id="_4-验证-l4-规则" tabindex="-1">4. 验证 L4 规则 <a class="header-anchor" href="#_4-验证-l4-规则" aria-label="Permalink to &quot;4. 验证 L4 规则&quot;">​</a></h2><p>回到 L4 规则列表，能看到规则卡片包含 <code>Relay</code> 标记，说明这条规则已经带上 Relay 链路。</p><p><img src="'+o+'" alt="L4 Relay 规则"></p><p>在客户端测试入口端口：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">VPS_A_I</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">P</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18096</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果后端是 HTTP 服务，也可以直接用浏览器打开：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://&lt;VPS_A_IP&gt;:18096</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你给入口端口绑定了域名或前置代理，也可以访问对应域名和端口。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>排查方向</th></tr></thead><tbody><tr><td>L4 规则保存了但连不上</td><td>检查 L4 监听端口是否被云安全组和系统防火墙放行。</td></tr><tr><td>规则卡片没有 <code>Relay</code> 标记</td><td>回到 L4 规则的 Relay 配置，确认已经添加 Relay 层并保存。</td></tr><tr><td>Relay 监听器可见但不可用</td><td>检查 Relay 的公网入口域名、端口、防火墙和证书自动签发状态。</td></tr><tr><td>入口能连通但后端无响应</td><td>检查最终出站节点是否能访问 <code>origin.emby.example.net:8096</code>。</td></tr><tr><td>用 HTTPS 客户端访问失败</td><td>L4 只转发 TCP，不自动为上游 HTTP 服务签发 HTTPS 证书；确认客户端协议和后端协议一致。</td></tr></tbody></table><h2 id="和-http-规则怎么选" tabindex="-1">和 HTTP 规则怎么选 <a class="header-anchor" href="#和-http-规则怎么选" aria-label="Permalink to &quot;和 HTTP 规则怎么选&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需求</th><th>推荐</th></tr></thead><tbody><tr><td>反代公费服/公益服 Emby Web 入口，解决观看必须挂代理</td><td>HTTP 规则</td></tr><tr><td>按域名、路径、HTTP 头处理 Web 流量</td><td>HTTP 规则</td></tr><tr><td>只想转发一个 TCP/UDP 端口</td><td>L4 规则</td></tr><tr><td>L4 流量需要经过中继链路</td><td>L4 规则 + Relay</td></tr></tbody></table>',40)])])}const k=e(p,[["render",c]]);export{P as __pageData,k as default};
